#[tokio::test]
async fn test_validation_browser_endpoint_invalid() {
    // Browser endpoint must be a valid ws:// or wss:// URL, not http://
    let engine_config: CrawlConfig =
        serde_json::from_str("{\"browser\":{\"endpoint\":\"http://not-websocket:3000\",\"mode\":\"always\"}}")
            .expect("config should parse");
    let engine_result = create_engine(Some(engine_config));
    let url = std::env::var("MOCK_SERVER_VALIDATION_BROWSER_ENDPOINT_INVALID").unwrap_or_else(|_| {
        let _ = common::mock_server_url();
        std::env::var("MOCK_SERVER_VALIDATION_BROWSER_ENDPOINT_INVALID").unwrap_or_else(|_| {
            format!(
                "{}/fixtures/{}",
                common::mock_server_url(),
                "validation_browser_endpoint_invalid"
            )
        })
    });
    let result = match engine_result {
        Err(e) => Err(e),
        Ok(engine) => scrape(&engine, &url).await,
    };
    assert!(result.is_err(), "expected call to fail");
    {
        let __e = result.as_ref().err().unwrap();
        assert!(
            format!("{:?}", __e).contains("endpoint") || __e.to_string().contains("endpoint"),
            "error message mismatch"
        );
    }
}

